/**
 * Configuration module for Voynich word position visualizer.
 * 
 * Transcription config (char ordering, display mappings, etc.) is loaded from
 * output/transcription_config.json - the single source of truth generated by
 * the Python processing scripts.
 * 
 * This file contains only presentation/viz-specific settings (colors, defaults).
 */

const Config = (function() {
  
  // These will be populated from transcription_config.json
  let CHAR_DISPLAY = {};
  let CHAR_ORDER = [];
  let AGGREGATION_DEFINITIONS = {};
  let _configLoaded = false;
  
  /**
   * Load transcription config from JSON (called by DataLoader on init).
   * @param {Object} config - Config object from transcription_config.json
   */
  function loadTranscriptionConfig(config) {
    CHAR_DISPLAY = config.char_display || {};
    CHAR_ORDER = config.char_order || [];
    AGGREGATION_DEFINITIONS = config.aggregations || {};
    _configLoaded = true;
  }
  
  /**
   * Check if config has been loaded.
   */
  function isConfigLoaded() {
    return _configLoaded;
  }
  
  // Position colors
  const POSITION_COLORS = {
    start: '#4a90d9',   // Blue
    middle: '#50c878',  // Green
    end: '#ff6b6b',     // Red
    only: '#9b59b6',    // Purple
  };
  
  // Diff colors
  const DIFF_COLORS = {
    positive: '#28a745',
    negative: '#dc3545',
    neutral: '#6c757d',
  };
  
  // Default settings
  const DEFAULTS = {
    aggregation: 'all',
    sortBy: 'start',
    useVoynichFont: true,
    showOnly: true,
    barWidth: 40,
    barGap: 8,
    chartPadding: { top: 40, right: 20, bottom: 60, left: 50 },
  };
  
  /**
   * Get display label for a character.
   */
  function getCharDisplay(char, useVoynichFont = false) {
    if (useVoynichFont) {
      const fontMap = {
        '1': 'i', '2': 'ii', '3': 'iii', '4': 'iiii',
        '6': 'e', '7': 'ee', '8': 'eee', '9': 'eeee',
        'C': 'ch', 'S': 'sh', 'T': 'cth', 'P': 'cph', 'F': 'cfh', 'K': 'ckh',
      };
      return fontMap[char] || char;
    }
    return CHAR_DISPLAY[char] || char;
  }
  
  /**
   * Sort characters according to preferred order.
   */
  function sortCharacters(chars) {
    const orderMap = new Map(CHAR_ORDER.map((c, i) => [c, i]));
    return [...chars].sort((a, b) => {
      const aIdx = orderMap.has(a) ? orderMap.get(a) : 999;
      const bIdx = orderMap.has(b) ? orderMap.get(b) : 999;
      return aIdx - bIdx;
    });
  }
  
  /**
   * Sort characters by a specific criterion.
   */
  function sortCharactersBy(charData, sortBy) {
    const entries = Object.entries(charData);
    
    switch (sortBy) {
      case 'total':
        entries.sort((a, b) => b[1].total - a[1].total);
        break;
      case 'start':
        entries.sort((a, b) => b[1].ratios.start - a[1].ratios.start);
        break;
      case 'middle':
        entries.sort((a, b) => b[1].ratios.middle - a[1].ratios.middle);
        break;
      case 'end':
        entries.sort((a, b) => b[1].ratios.end - a[1].ratios.end);
        break;
      case 'position':
        // Order from most start-preferring (top) to most end-preferring (bottom)
        // Uses (start - end) ratio difference: positive = start preference, negative = end preference
        entries.sort((a, b) => {
          const aDiff = (a[1].ratios.start || 0) - (a[1].ratios.end || 0);
          const bDiff = (b[1].ratios.start || 0) - (b[1].ratios.end || 0);
          return bDiff - aDiff;
        });
        break;
      case 'alpha':
        return sortCharacters(entries.map(e => e[0]));
      default:
        entries.sort((a, b) => b[1].total - a[1].total);
    }
    
    return entries.map(e => e[0]);
  }
  
  /**
   * Get aggregation description.
   */
  function getAggregationDescription(name) {
    if (AGGREGATION_DEFINITIONS[name]) {
      return AGGREGATION_DEFINITIONS[name].description;
    }
    return name;
  }
  
  return {
    // Loaded from transcription config
    get CHAR_DISPLAY() { return CHAR_DISPLAY; },
    get CHAR_ORDER() { return CHAR_ORDER; },
    get AGGREGATION_DEFINITIONS() { return AGGREGATION_DEFINITIONS; },
    // Presentation config (static)
    POSITION_COLORS,
    DIFF_COLORS,
    DEFAULTS,
    // Functions
    loadTranscriptionConfig,
    isConfigLoaded,
    getCharDisplay,
    sortCharacters,
    sortCharactersBy,
    getAggregationDescription,
  };
})();
